import React, { Component } from "react";

class Footer extends Component {
  render() {
    if (this.props.sharedBasicInfo) {
      var networks = this.props.sharedBasicInfo.social.map(function (network) {
        return (
          <span key={network.name} className="m-4">
            <a 
              href={network.url} 
              target="_blank" 
              rel="noopener noreferrer"
              style={{ 
                color: "var(--header-text)", // Follows theme text color
                fontSize: "25px", 
                transition: "color 0.3s ease" 
              }}
              /* Subtle gold glow on hover */
              onMouseEnter={(e) => e.target.style.color = "#AE944F"}
              onMouseLeave={(e) => e.target.style.color = "var(--header-text)"}
            >
              <i className={network.class}></i>
            </a>
          </span>
        );
      });
    }

    return (
      <footer style={{ 
        background: "var(--body-background)", // Matches the rest of the site
        padding: "50px 0",
        transition: "background 0.6s ease" 
      }}>
        <div className="col-md-12">
          <div className="social-links" style={{ textAlign: "center", marginBottom: "30px" }}>
            {networks}
          </div>

          <div className="copyright py-4 text-center">
            <div className="container">
              <small style={{ 
                color: "var(--text-color)", 
                opacity: 0.6, 
                fontSize: "14px",
                transition: "color 0.6s ease" 
              }}>
                Copyright &copy;{" "}
                {this.props.sharedBasicInfo
                  ? this.props.sharedBasicInfo.name
                  : "???"}
              </small>
            </div>
          </div>
        </div>
      </footer>
    );
  }
}

export default Footer;
